  const msg = JSON.parse(e.data);
  exibirMensagem(msg);
});

// Fechar conexão:
ws.close();
```

**Server-Sent Events (SSE)** — para streaming de dados do servidor para o cliente (uma direção):
```
// Cliente:
const eventSource = new EventSource('/api/notificacoes');

eventSource.addEventListener('message', (e) => {
  const dados = JSON.parse(e.data);
  exibirNotificacao(dados);
});

eventSource.addEventListener('error', () => {
  console.log('Reconectando...');
  // Browser reconecta automaticamente!
});

// Para encerrar:
eventSource.close();
```

**Streaming de respostas** com fetch — processar dados progressivamente:
```
async function lerStream(url) {
  const response = await fetch(url);
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let texto = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    texto += decoder.decode(value, { stream: true });
    atualizarUI(texto); // atualiza progressivamente!
  }
}
// Base de como streaming de LLMs funciona!
```

