**Cache API** (parte dos Service Workers) — armazenar respostas HTTP para uso offline:
```
// Armazenar no cache:
async function cachearPaginas() {
  const cache = await caches.open('v1');
  await cache.addAll([
    '/',
    '/app.js',
    '/estilo.css',
    '/offline.html'
  ]);
}

// Buscar do cache:
async function buscarDoCache(request) {
  const cached = await caches.match(request);
  return cached || fetch(request);
}
```

**Padrão de loading states** — gerenciar estados de carregamento na UI:
```
async function carregarDados() {
  const loading = document.querySelector('#loading');
  const content = document.querySelector('#content');
  const error = document.querySelector('#error');

  loading.style.display = 'block';
  content.style.display = 'none';
  error.style.display = 'none';

  try {
    const dados = await fetch('/api/dados').then(r => r.json());
    content.innerHTML = renderizarDados(dados);
    content.style.display = 'block';
  } catch (e) {
    error.textContent = 'Erro ao carregar: ' + e.message;
    error.style.display = 'block';
  } finally {
    loading.style.display = 'none';
  }
}
```

**Erros comuns com async/await** — armadilhas a evitar:
```
// ERRADO — await fora de async:
const dados = await fetch('/api'); // SyntaxError!

// ERRADO — esquecer de await:
function buscar() {
  const dados = fetch('/api'); // retorna Promise, não dados!
  console.log(dados); // Promise { <pending> }
}

// CERTO:
async function buscar() {
  const dados = await fetch('/api');
  console.log(await dados.json()); // objeto de dados
}
```

**Unhandled Promise rejections** — um erro grave que pode derrubar aplicações Node.js:
```
// Ruim — rejeição não tratada!
const p = buscarDados();
// se buscarDados() rejeitar, sem tratamento = crash em Node!

// Melhor — sempre tratar:
buscarDados()
  .then(dados => processar(dados))
  .catch(erro => console.error(erro));

// Ou com async/await:
try {
  const dados = await buscarDados();
} catch (e) {
  console.error(e);
}

// Global handler (último recurso):
process.on('unhandledRejection', (reason) => {
  console.error('Não tratado:', reason);
});
```

**Promise chaining vs async/await** — ambos são válidos, prefira legibilidade:
```
// Promise chaining:
buscarUsuario(id)
  .then(u => buscarPosts(u.id))
  .then(posts => posts.filter(p => p.publicado))
  .then(filtrados => exibir(filtrados))
  .catch(console.error);

// Async/await equivalente:
async function carregarPosts(id) {
  try {
    const usuario = await buscarUsuario(id);
    const posts = await buscarPosts(usuario.id);
    const filtrados = posts.filter(p => p.publicado);
    exibir(filtrados);
  } catch (e) {
    console.error(e);
  }
}
```

**Padrões avançados** — Promise com `resolve`/`reject` externo (útil para integrar código legado com callbacks):
```
// Converter callback para Promise:
function lerArquivo(caminho) {
  return new Promise((resolve, reject) => {
    fs.readFile(caminho, 'utf8', (erro, dados) => {
      if (erro) reject(erro);
      else resolve(dados);
    });
  });
}

// Agora pode usar com async/await:
const conteudo = await lerArquivo('dados.txt');
```

**Concorrência limitada** — executar N operações ao mesmo tempo, não mais que isso (evitar sobrecarregar servidor):
```
async function processarEmLotes(items, tamanhoLote = 5) {
  const resultados = [];
  for (let i = 0; i < items.length; i += tamanhoLote) {
    const lote = items.slice(i, i + tamanhoLote);
    const loteResultados = await Promise.all(
      lote.map(item => processar(item))
    );
    resultados.push(...loteResultados);
  }
  return resultados;
}
// Processa 5 por vez, em sequência de lotes
```

**`Promise.resolve()` e `Promise.reject()`** criam Promises já resolvidas/rejeitadas — úteis para testes e funções que podem ser síncronas ou assíncronas:
```
// Promise já resolvida:
const p1 = Promise.resolve(42);
await p1; // 42 imediatamente

// Promise já rejeitada:
const p2 = Promise.reject(new Error('ops'));

// Normalizar função que pode ser sync ou async:
function buscar(id) {
  if (cache.has(id)) {
    return Promise.resolve(cache.get(id)); // sync, mas retorna Promise
  }
  return fetch(`/api/${id}`).then(r => r.json()); // async
}
// Caller sempre usa await sem se preocupar!
```

Um exemplo completo e real — buscar dados de uma API paginada:
```
async function buscarTodos(baseUrl) {
  let pagina = 1;
  const todos = [];

  while (true) {
    const res = await fetch(`${baseUrl}?page=${pagina}&limit=20`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const { dados, totalPaginas } = await res.json();
    todos.push(...dados);

    if (pagina >= totalPaginas) break;
    pagina++;
  }

  return todos;
}
```

**Top-level await** (ES2022) — permite usar `await` no nível superior de módulos ES6, sem precisar de função `async`:
```
// Antes (era necessário wrap em async):
(async () => {
  const dados = await fetch('/config.json').then(r => r.json());
  iniciarApp(dados);
})();

// Agora com top-level await em módulos:
const dados = await fetch('/config.json').then(r => r.json());
iniciarApp(dados);

// Só funciona em arquivos com type='module'!
// O módulo importador espera o await terminar
```

**Observables** (padrão rxjs) — para fluxos de dados ao longo do tempo (mais poderoso que Promises para eventos múltiplos):
```
import { fromEvent, debounceTime, map } from 'rxjs';

// Observable de cliques:
const cliques$ = fromEvent(document, 'click');

// Observable de input com debounce:
const busca$ = fromEvent(input, 'input').pipe(
  debounceTime(300),
  map(e => e.target.value)
);

busca$.subscribe(termo => {
  buscarResultados(termo);
});
```
Promises são para UM valor futuro. Observables são para MÚLTIPLOS valores ao longo do tempo.

**GraphQL + fetch** — querying APIs modernas:
```
async function query(endpoint, graphqlQuery, variaveis = {}) {
  const response = await fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      query: graphqlQuery,
      variables: variaveis
    })
  });

  const { data, errors } = await response.json();
  if (errors) throw new Error(errors[0].message);
  return data;
}

const resultado = await query(
  'https://api.github.com/graphql',
  `query { viewer { login } }`,
);
```

